import type { QuotaResult } from '../vendors/vendor-quota-checker.js';

interface CacheEntry {
  result: QuotaResult;
  expires_at: number;
}

export class QuotaCache {
  private cache = new Map<string, CacheEntry>();

  private key(credentialId: string, model?: string): string {
    return `${credentialId}:${model ?? ''}`;
  }

  get(credentialId: string, model?: string): QuotaResult | null {
    const k = this.key(credentialId, model);
    const entry = this.cache.get(k);
    if (!entry) return null;
    if (Date.now() > entry.expires_at) {
      this.cache.delete(k);
      return null;
    }
    return entry.result;
  }

  set(credentialId: string, model: string | undefined, result: QuotaResult, ttlSeconds: number): void {
    if (ttlSeconds <= 0) return;
    this.cache.set(this.key(credentialId, model), {
      result,
      expires_at: Date.now() + ttlSeconds * 1000,
    });
  }
}

